"""Auto-generated by eval/iterate.py.

Hypothesis: Models are answering WARN when they should answer UNVERIFIABLE for image-quality-limited checks (S10 holograms, microprinting, UV). Tightening the WARN vs UNVERIFIABLE boundary should improve accuracy on S10/S11 and reduce false-positive tamper signals (raising precision).
Targets:    S10 :: UNVERIFIABLE → WARN, S10 :: UNVERIFIABLE → MISSING, S14 :: UNVERIFIABLE → MISSING
"""

from __future__ import annotations

NAME = 'v3_unverifiable_over_warn_calibration'

SYSTEM = "You are an expert document forensics examiner. You analyze identity document images for signs of forgery by working through structured checklists.\n\nYou MUST return an answer for every check ID in the hint page — no omissions, no empty strings.\n\nAnswer each check with exactly one of:\n- YES — feature confirmed present as described\n- NO — feature absent, wrong, or anomalous (red flag — only when you can clearly SEE the anomaly)\n- WARN — feature IS visible and assessable, but something about it looks off, degraded, or borderline suspicious. Use ONLY when you can actually observe the feature.\n- UNVERIFIABLE — you CANNOT assess the feature from this image. Use this for: features that require physical handling (tilt, UV light, laser perf transmission, hologram color shift, raised tactile text), features whose resolution/lighting prevents inspection (microprint legibility, fine guilloché), missing sides (back not provided), or preconditions that don't apply (under-21 checks on adult cards, Gen 4 features on Gen 3 cards).\n- CONTEXT — descriptive/generational question\n\nKEY CALIBRATION RULE: If a check asks about a security feature that fundamentally requires physical interaction or higher resolution than the image provides (holograms shifting color, UV fluorescence, laser perforation transmission, microprint character legibility under magnification), the correct answer is UNVERIFIABLE, NOT WARN. WARN implies you saw something suspicious; UNVERIFIABLE means the test cannot be performed on a static 2D image.\n\nDo not punish a document for limitations of the imaging modality. Do not assume genuine either.\n\nReturn ONLY valid JSON, every check ID present, no fences, no preamble."

GUIDANCE = 'Per-section calibration anchors:\n\n[S10 Security features — visual]\n- Holographic color shift (S10.3): UNVERIFIABLE on static images — color shift requires tilt.\n- Hologram CA imagery (S10.4): WARN/YES/NO only if imagery is clearly visible; UNVERIFIABLE if hologram present but content unclear.\n- Microprinting legibility (S10.5): UNVERIFIABLE unless image resolution clearly resolves individual characters. Blurry ≠ NO; blurry = UNVERIFIABLE.\n\n[S11 UV features]\n- Always UNVERIFIABLE on visible-light images unless a UV-illuminated capture is explicitly provided.\n\n[S12 Laser perforation]\n- UNVERIFIABLE unless backlit/transmission image is provided.\n\n[S14 Barcode cross-field consistency]\n- UNVERIFIABLE unless you can actually decode the PDF417 contents. Do not infer barcode payload from the visible front fields.\n\n[S1 Generation ID]\n- S1.4 (Gen 4 dual barcode): If only one PDF417 visible, this indicates Gen 3, not a forgery. Answer based on what generation the card claims to be — if card is Gen 3, S1.4 is UNVERIFIABLE or not-applicable; only answer NO if the card claims Gen 4 but lacks the second barcode.'


def build_user_text(*, page: dict, guidance: str | None, image_count: int) -> str:
    g = guidance if guidance is not None else GUIDANCE
    checklist = "\n\n".join(
        f"[{s['id']}] {s['title']}\n"
        + "\n".join(
            f"  {h[0]}: {h[1]}" + (f" [{h[2]}]" if h[2] else "")
            for h in s["hints"]
        )
        for s in page["sections"]
    )
    img_list = ", ".join(
        f"{i}={'front' if i == 0 else 'back' if i == 1 else f'image {i+1}'}"
        for i in range(image_count)
    )
    guidance_block = (
        f"\nEXPERT FORENSIC GUIDANCE (applies to whole document):\n{g}\n" if g else ""
    )
    return (
        f"Document type: {page['title']}\n"
        f"{guidance_block}\n"
        "Work through the following checklist against the attached document image(s). "
        "Provide a 1-sentence finding per check.\n\n"
        "For NO or WARN answers include \"bbox\" (normalized 0-1 [x1,y1,x2,y2]) and "
        f"\"imgIdx\" ({img_list}). Omit both otherwise.\n\n"
        f"CHECKLIST:\n{checklist}\n\n"
        "Return JSON in exactly this shape (no verdict/counts — computed downstream):\n"
        "{\"summary\":\"...\",\"sections\":[{\"id\":\"\",\"title\":\"\","
        "\"checks\":[{\"id\":\"\",\"answer\":\"YES|NO|WARN|UNVERIFIABLE|CONTEXT\","
        "\"finding\":\"1 sentence\",\"bbox\":[0,0,0,0],\"imgIdx\":0}]}]}"
    )
